    16→
    17→function buildCliArgs(args: MittwaldAppUploadArgs, installationId: string): string[] {
    18→  const cliArgs: string[] = ['app', 'upload', installationId, '--source', args.source];
    19→
    20→  if (args.quiet) cliArgs.push('--quiet');
    21→  if (args.sshUser) cliArgs.push('--ssh-user', args.sshUser);
    22→  if (args.sshIdentityFile) cliArgs.push('--ssh-identity-file', args.sshIdentityFile);
    23→  if (Array.isArray(args.exclude)) {
    24→    for (const pattern of args.exclude) {
    25→      cliArgs.push('--exclude', pattern);
    26→    }
    27→  }
    28→  if (args.dryRun) cliArgs.push('--dry-run');
    29→  if (args.delete) cliArgs.push('--delete');
    30→  if (args.remoteSubDirectory) cliArgs.push('--remote-sub-directory', args.remoteSubDirectory);
    31→
    32→  return cliArgs;
    33→}
    34→
    35→function mapCliError(error: CliToolError, args: MittwaldAppUploadArgs): string {
    36→  const combined = `${error.stdout ?? ''}\n${error.stderr ?? ''}`.toLowerCase();
    37→
    38→  if (combined.includes('not found') && combined.includes('installation')) {
    39→    return `App installation not found. Please verify the installation ID: ${args.installationId}.\nError: ${error.stderr || error.message}`;
    40→  }
    41→
    42→  if (combined.includes('rsync')) {
    43→    return `rsync is required but not available. Please install rsync on your system.\nError: ${error.stderr || error.message}`;
    44→  }
    45→
    46→  if (combined.includes('source') && combined.includes('not found')) {
    47→    return `Source directory not found: ${args.source}.\nError: ${error.stderr || error.message}`;
    48→  }
    49→
    50→  return error.message;
    51→}
    52→
    53→function buildSuccessMessage(args: MittwaldAppUploadArgs): string {
    54→  if (args.dryRun) return 'Dry run completed successfully';
    55→  return 'App uploaded successfully';
    56→}
    57→
    58→function parseQuietOutput(output: string): string | undefined {
    59→  const trimmed = output.trim();
    60→  if (!trimmed) return undefined;
    61→  const lines = trimmed.split(/\r?\n/);
    62→  return lines.at(-1);
    63→}
    64→
    65→export const handleAppUploadCli: MittwaldCliToolHandler<MittwaldAppUploadArgs> = async (args) => {
    66→  if (!args.installationId) {
    67→    return formatToolResponse('error', 'Installation ID is required. Please provide the installationId parameter.');
    68→  }
    69→
    70→  if (!args.source) {
    71→    return formatToolResponse('error', 'Source directory is required. Please provide the source parameter.');
    72→  }
    73→
    74→  const argv = buildCliArgs(args, args.installationId);
    75→
    76→  try {
    77→    const result = await invokeCliTool({
    78→      toolName: 'mittwald_app_upload',
    79→      argv,
    80→      parser: (stdout, raw) => ({ stdout, stderr: raw.stderr }),
    81→      cliOptions: {
    82→        timeout: 600000,
    83→        env: {
    84→          MITTWALD_NONINTERACTIVE: '1',
    85→        },
    86→      },
    87→    });
    88→
    89→    const stdout = result.result.stdout || '';
